import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How much protein do you need per day?", a: "Protein needs vary by body weight, activity level, age, and goal. Active people and those losing weight or building muscle often need more than sedentary adults." },
  { q: "How do you calculate protein needs?", a: "Multiply body weight in kilograms by a protein target, such as 0.8 g/kg for sedentary adults or 1.6 to 2.2 g/kg for muscle and performance goals." },
  { q: "Does more protein mean more muscle?", a: "Protein supports muscle growth, but muscle also requires progressive training, adequate calories, recovery, and time." },
  { q: "What are the best sources of protein?", a: "Common sources include lean meat, fish, eggs, dairy, beans, lentils, soy foods, protein powders, nuts, and seeds." },
  { q: "Can you eat too much protein?", a: "Very high protein may be unnecessary and can crowd out other nutrients. People with kidney disease should follow medical guidance." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const targets: Record<string, number> = { "Lose weight": 1.8, Maintain: 1.2, "Build muscle": 1.6, "Athletic performance": 2.0 };

export default function ProteinCalculator() {
  const [age, setAge] = useState(30);
  const [gender, setGender] = useState("Male");
  const [height, setHeight] = useState(70);
  const [weight, setWeight] = useState(180);
  const [activity, setActivity] = useState("Moderate");
  const [goal, setGoal] = useState("Build muscle");
  const result = useMemo(() => {
    const kg = weight * 0.45359237;
    let perKg = targets[goal] + (activity === "Athlete" ? 0.2 : activity === "Sedentary" ? -0.2 : 0);
    if (goal === "Maintain" && activity === "Sedentary") perKg = 0.8;
    perKg = Math.min(2.2, Math.max(0.8, perKg));
    return { grams: kg * perKg, perKg, perLb: perKg / 2.20462 };
  }, [weight, activity, goal]);
  const rows = [["Sedentary", 0.8, 0.36], ["Light Activity", 1.0, 0.45], ["Moderate Activity", 1.2, 0.54], ["Build Muscle", 1.6, 0.73], ["Athletic Performance", 2.0, 0.91], ["Weight Loss", 1.8, 0.82]];
  return (
    <>
      <SEOHead title="Free Protein Calculator Online - Calculate Daily Protein Intake Instantly | CalcHive" description="Free online protein calculator. Calculate your recommended daily protein intake based on your goal, body weight and activity level instantly. 100% free, no signup required." canonical="/protein-calculator" keywords="free protein calculator, daily protein intake calculator free online, how much protein per day calculator free, protein needs calculator free, muscle building protein calculator free" category="Health Calculators" breadcrumbName="Free Protein Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Protein Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate daily protein needs from your body weight, activity, and goal.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Activity level</label><select value={activity} onChange={(e) => setActivity(e.target.value)} className={inputClass}><option>Sedentary</option><option>Light</option><option>Moderate</option><option>Athlete</option></select></div><div><label className="text-sm font-semibold block mb-2">Goal</label><select value={goal} onChange={(e) => setGoal(e.target.value)} className={inputClass}>{Object.keys(targets).map((x) => <option key={x}>{x}</option>)}</select></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Daily Protein</p><p className="text-5xl sm:text-6xl font-black text-white">{Math.round(result.grams)}g</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Protein per kg</p><p className="text-lg font-extrabold">{result.perKg.toFixed(2)} g/kg</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Protein per lb</p><p className="text-lg font-extrabold">{result.perLb.toFixed(2)} g/lb</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Daily Protein Intake for Free</h2><p className="text-muted-foreground leading-relaxed">This calculator converts your weight to kilograms and multiplies it by a goal-based protein target.</p><h2 className="text-2xl font-bold">How Much Protein Do You Need to Build Muscle</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Daily Protein Intake by Goal and Body Weight</caption><thead className="bg-muted/60"><tr>{["Goal", "Protein per kg", "Protein per lb", "For 150lb Person", "For 200lb Person"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map(([goalName, kg, lb]) => <tr key={String(goalName)}><td className="py-2.5 px-3 font-semibold">{goalName}</td><td className="py-2.5 px-3">{kg} g/kg</td><td className="py-2.5 px-3">{lb} g/lb</td><td className="py-2.5 px-3">{Math.round(Number(lb) * 150)}g</td><td className="py-2.5 px-3">{Math.round(Number(lb) * 200)}g</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Daily Protein Needs Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/protein-calculator" headingLevel="h3" /></main>
    </>
  );
}


